mapper.update:
update tb_qc_test_mst
set       req_tester_id = #{vo.reqTesterId}
        , area_cd       = #{vo.areaCd}
        , storage_cd    = #{vo.storageCd}
        , req_qty       = #{vo.reqQty}
        , TEST_STATE    = #{vo.testState}
        , PASS_STATE    = #{vo.passState}
        , upd_id        = #{userId}
        , upd_dt        = getdate()
where  test_no  = #{testNo}
and    REQ_DATE = #{reqDate}

update tb_qc_test_mst
set     req_tester_id = #{reqTesterId}
      , area_cd       = #{areaCd}
      , storage_cd    = #{storageCd}
      , req_qty       = #{reqQty}
      , TEST_STATE    = #{testState}
      , PASS_STATE    = #{passState}
      , upd_id        = #{userId}
      , upd_dt        = getdate()
where  qc_test_id     = #{qcTestId}

update tb_qc_test_mst
set    req_qty	 	        = #{reqQty}
      ,test_qty	 	        = #{testQty}
      ,sample_qty	 	    = #{sampleQty}
      ,tester_id		 	= #{testerId}
      ,order_tester_id 	    = #{orderTesterId}
      ,confirm_tester_id    = #{confirmTesterId}
      ,sample_tester_id 	= #{sampleTesterId}
      ,etc			 	    = #{etc}
      ,qc_cd         	    = #{qcCd}

      ,test_date	 	    = #{testDate}


      ,confirm_date 	    = #{confirmDate}

      ,test_state	 	    = #{testState}
      ,pass_state	 	    = #{passState}
      ,upd_id               = #{userId}
      ,upd_dt               = getdate()
where  qc_test_id = #{qcTestId}
